+    // Remove script blocks and foreignObject (can embed HTML).
+    let sanitized = svgString
+        .replace(/<script[\s\S]*?>[\s\S]*?<\/script\s*>/gi, '')
+        .replace(/<foreignObject[\s\S]*?>[\s\S]*?<\/foreignObject\s*>/gi, '')
